'use client'
import { cn } from '@cascivo/core'
import type { ReactNode } from 'react'
import styles from './page-header.module.css'

export interface PageHeaderProps {
  title: string
  description?: string
  breadcrumb?: ReactNode
  actions?: ReactNode
  className?: string
}

export function PageHeader({
  title,
  description,
  breadcrumb,
  actions,
  className,
}: PageHeaderProps) {
  return (
    <header className={cn(styles['header'], className)}>
      {breadcrumb && <div className={styles['breadcrumb']}>{breadcrumb}</div>}
      <div className={styles['row']}>
        <h1 className={styles['title']}>{title}</h1>
        {actions && <div className={styles['actions']}>{actions}</div>}
      </div>
      {description && <p className={styles['description']}>{description}</p>}
    </header>
  )
}

@layer cascivo.component {
  .header {
    display: flex;
    flex-direction: column;
    gap: var(--cascivo-space-2);
  }

  .breadcrumb {
    color: var(--cascivo-color-text-muted);
  }

  .row {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: var(--cascivo-space-4);
    flex-wrap: wrap;
  }

  .title {
    margin: 0;
    font-size: var(--cascivo-font-size-2xl, 1.5rem);
    font-weight: var(--cascivo-font-weight-bold, 700);
    color: var(--cascivo-color-text);
    line-height: 1.2;
  }

  .actions {
    display: flex;
    align-items: center;
    gap: var(--cascivo-space-2);
    flex-shrink: 0;
  }

  .description {
    margin: 0;
    color: var(--cascivo-color-text-muted);
    font-size: var(--cascivo-font-size-sm);
  }
}
